import React from "react";

class ProfileStatus extends React.Component {
  state = {
    editMode: true,
    statusText: "Hi there",
  };

  render() {
    return (
      <div>
        {!this.state.editMode ? (
          <div>{this.state.statusText}</div>
        ) : (
          <div>
            <input value={this.state.statusText}></input>
          </div>
        )}
      </div>
    );
  }
}

export default ProfileStatus;
